INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D1', '2026年1月1日正式实施的第四套生命表（2025版），其最核心的更新依据是？', '保险行业投资收益率的变化趋势', '保险人群死亡率结构的显著变化', '保险产品预定利率的下调要求', '保险消费者投诉率统计数据', 'B', '生命表是反映保险人群死亡概率的核心精算工具。第四套生命表距上一版已10年，期间人口平均预期寿命延长、死亡率下降约20%，这是更新生命表的根本依据。投资收益率影响的是预定利率，预定利率下调是独立政策，投诉率与生命表无关。'),
('D1', '根据2026年2月1日实施的《金融机构产品适当性管理办法》，投保前强制要求进行的"风险测评问卷"最核心的目的是？', '收集客户信息用于精准营销', '评估客户风险承受能力，将合适的产品卖给合适的人', '限制低收入群体购买任何保险产品', '为保险公司精算定价提供数据支撑', 'B', '适当性管理办法核心原则是"卖者尽责、买者自负"，要求保险公司评估客户风险承受能力后推荐对应等级的产品，防止错配销售。风险测评不是营销手段，不限制低收入者购买所有保险，也不用于精算定价。'),
('D1', '某保险公司AI核保系统对某投保人做出"拒保"决定，投保人要求解释原因。根据保险科技伦理与消费者权益保护要求，以下做法正确的是？', '以"商业机密"为由拒绝提供任何解释，仅告知拒保结果', '向投保人说明影响核保结论的关键因素和大致逻辑，同时保护模型训练数据等商业敏感信息', '向投保人公开AI模型的全部训练数据和算法源代码', '要求投保人自行委托第三方机构审计AI模型', 'B', '金融领域AI应用的可解释性是监管重点要求。保险公司应向消费者提供有意义的解释（影响决策的关键因素），而非"黑箱"拒保。但完全公开模型训练数据和源代码不现实且可能泄露商业秘密和客户隐私。正确做法是平衡透明度与商业保护。'),
('D1', '2026年多项保险新规叠加落地：第四套生命表实施、适当性管理办法生效、非车险报行合一全面推进。以下哪项准确反映了这些政策的共同监管导向？', '放松市场准入门槛，鼓励更多主体参与保险市场竞争', '以"规范销售行为、强化数据驱动、保护消费者权益"为主线，推动行业从规模扩张转向质量发展', '统一降低所有保险产品费率，减轻消费者负担', '限制保险科技应用，回归传统人工核保和纸质化运营', 'B', '第四套生命表使定价更精准（数据驱动）、适当性管理办法规范销售行为（保护消费者）、报行合一遏制恶性竞争（规范市场），三者共同指向"规范+精准+保护消费者"的监管导向。新规并未放松准入，也未统一降价（生命表甚至使部分产品涨价），更非限制科技应用。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D2', '香农信息论中，将热力学"熵"引入信息领域。关于"熵"与"信息"的关系，以下说法正确的是？', '熵是系统有序程度的度量，信息是系统无序程度的度量', '熵是系统无序程度的度量，信息是系统有序程度的度量（表现为负熵）', '熵和信息都是系统无序程度的度量', '熵和信息是同一概念的不同表述', 'B', '这是软考高频考点。熵度量系统的无序/不确定性，信息则消除不确定性，度量系统的有序程度，表现为负熵。二者方向相反，非同一概念。'),
('D2', '我国新型基础设施建设分为信息基础设施、融合基础设施、创新基础设施三大类。以下分类正确的是？', '5G网络—融合基础设施；智能交通—信息基础设施；重大科技平台—创新基础设施', '人工智能算力平台—信息基础设施；智能交通—融合基础设施；科教基础设施—创新基础设施', '云计算数据中心—融合基础设施；5G网络—创新基础设施；智能能源—信息基础设施', '人工智能算力平台—创新基础设施；5G网络—信息基础设施；智能交通—信息基础设施', 'B', '记忆口诀——"技术新"属信息基础设施（5G/AI/云计算/区块链），"应用新"属融合基础设施（智能交通/智慧能源），"平台新"属创新基础设施（重大科技/科教/产业技术创新平台）。'),
('D2', '信息系统的生命周期分为五个阶段：系统规划→系统分析→系统设计→系统实施→系统运行维护。其中"概要设计和详细设计"属于哪个阶段的工作内容？', '系统规划', '系统分析', '系统设计', '系统实施', 'C', '各阶段核心产出——系统规划（可行性分析、开发计划）→系统分析（需求分析）→系统设计（概要设计、详细设计）→系统实施（编码、测试）→系统运行维护。概要设计和详细设计属于系统设计阶段。'),
('D2', '某保险核心系统升级项目面临需求频繁变更的情况，以下哪种开发模型更适合？', '瀑布模型——严格按阶段推进，每个阶段完成后不可回退', 'V模型——强调测试与开发的对应关系，但阶段仍为线性推进', '敏捷开发——以迭代增量方式交付，每个迭代可根据反馈调整需求优先级', '螺旋模型——仅适用于超大型项目，每次迭代必须进行完整风险评估', 'C', '瀑布模型和V模型均为线性推进，缺乏灵活性，难以应对需求变更。螺旋模型虽支持迭代但流程较重。敏捷开发以短周期迭代、快速响应变更、持续交付价值为核心，最适合需求频繁变更的场景。'),
('D2', '某保险公司信息科技部在制定IT治理规划时参考COBIT框架，以下哪项属于COBIT框架中IT治理的核心目标，而非IT管理的目标？', '确保IT服务台在2小时内响应所有用户故障申报', '确保IT战略与公司业务战略对齐，实现IT交付价值最大化', '规定数据库备份必须在每日凌晨2点自动执行', '为开发团队制定代码提交前的单元测试覆盖率≥80%的要求', 'B', 'IT治理关注"做正确的事"——战略对齐、价值交付、风险管理、资源优化。IT管理关注"正确地做事"——具体运营执行，如响应时间、备份策略、测试规范均属于管理层面。区分治理与管理的层次是COBIT的核心思想。'),
('D2', '某保险理赔系统在一个月内发生了3次相同的数据库连接超时故障，每次事件管理团队均快速重启服务恢复运行。从ITSM最佳实践角度，下一步最应采取的行动是？', '维持现状，继续依赖事件管理快速恢复即可', '升级为问题管理，分析3次重复事件的根本原因并提出永久解决方案', '将数据库连接超时定义为"已知错误"，不再做任何处理', '直接更换数据库供应商，无需进行根因分析', 'B', '事件管理目标是快速恢复服务，但不查找根因。当同类事件重复发生时，应升级为问题管理，查找根本原因并实施永久解决方案以防再次发生。仅靠事件管理治标不治本，已知错误仍需记录解决方案，更换供应商不经过根因分析属于盲目决策。'),
('D2', '某保险公司需要重构理赔系统，要求：核心理赔数据必须保证ACID事务一致性，同时需支持海量理赔影像文件的弹性存储和高吞吐访问。以下架构方案最合理的是？', '全部使用关系型数据库，将影像文件以BLOB字段存储在数据库表中', '全部使用NoSQL文档数据库，牺牲事务一致性换取存储弹性', '核心理赔业务数据使用关系型数据库保证事务一致性，影像文件使用对象存储服务独立管理，通过业务标识关联', '使用关系型数据库存储影像文件路径，影像文件存储在应用服务器本地磁盘', 'C', '核心业务数据需要ACID事务保证（关系型数据库），但影像文件不适合BLOB方式存储在数据库中——会导致数据库膨胀、备份困难、查询性能下降。完全放弃事务一致性不可接受，应用服务器本地磁盘无法保证高可用和弹性扩展。正确方案是"关系型数据库+对象存储"的混合架构，各取所长。'),
('D2', '某保险项目在上线后发现：系统功能均按需求规格说明书实现，但业务部门认为系统"不好用"，实际使用率极低。从软件工程角度分析，最可能的根本原因是？', '编码质量差导致系统运行缓慢', '需求分析阶段仅采集了功能需求，未充分挖掘业务用户的实际工作流程和使用场景需求', '测试覆盖率不足导致存在大量功能缺陷', '运维团队部署操作失误', 'B', '题目明确"功能均按需求规格说明书实现"且问题不是性能或缺陷，也不是部署问题。"按规格实现却不好用"是典型的需求分析不充分问题——只采集了"做什么"的功能需求，忽略了"怎么用"的用户体验和工作场景需求。这属于需求工程中"需求获取不完整"的典型场景。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D3', '某保险公司员工收到一封邮件，声称来自公司IT部门，要求点击链接重置办公系统密码。该邮件发件人地址为 it-support@company-lnsurance.com（注意"l"非"i"）。这属于哪种攻击方式？', 'DDoS攻击', '钓鱼攻击（Phishing）', 'SQL注入攻击', '缓冲区溢出攻击', 'B', '钓鱼攻击通过伪造可信来源的邮件/网站，诱导用户点击恶意链接或提交敏感信息。发件人地址中用"lnsurance"冒充"insurance"是典型的域名仿冒手法。DDoS是流量洪泛攻击，SQL注入是针对数据库的代码注入，缓冲区溢出是针对程序内存的攻击。'),
('D3', '关于企业密码安全管理，以下做法最规范的是？', '为方便记忆，所有系统使用同一复杂密码', '将密码记录在加密的密码管理器中，各系统使用独立的高强度密码', '将密码写在便签纸上贴在显示器旁边以便随时查看', '使用姓名拼音加生日组合作为密码，确保不会忘记', 'B', '密码管理最佳实践——使用密码管理器生成并存储独立的高强度密码。所有系统共用一个密码，一旦泄露将全部沦陷。便签贴显示器是最常见的物理泄露风险。姓名+生日组合极易被社工攻击猜出。'),
('D3', '2026年已有多起利用深度伪造（Deepfake）技术冒充企业高管语音电话，诱骗财务人员紧急转账的案例。面对"高管"来电要求紧急大额转账，以下应对措施最有效的是？', '来电者能准确说出公司内部信息，声音也确认是高管本人，立即执行转账', '通过另一种独立渠道（如当面确认或拨打高管已知手机号）核实身份后再决定', '拒绝所有电话转账请求，改为仅接受邮件指令', '录音保存后执行转账，若有问题事后追查', 'B', '深伪技术可高度仿冒声音甚至视频，仅靠声音确认已不可靠。邮件同样可能被伪造或劫持。事后追查无法挽回已转出资金。最有效的方法是"带外验证"——通过与来电渠道无关的独立渠道核实身份，打破攻击者控制的信息通道。'),
('D3', '某保险公司数据安全团队发现：员工频繁通过个人网盘同步含客户信息的业务报表，同时公司核心系统仍使用RSA-2048加密传输数据。结合2026年"先存储、后解密"攻击趋势，以下风险评估和应对策略最准确的是？', '内部泄露风险仅来自外部黑客，员工使用个人网盘不构成威胁；RSA-2048在当前仍安全无需变更', '员工使用个人网盘属于内部数据泄露高风险行为应立即管控；同时RSA-2048加密的数据可能已被截获存储、等待量子计算成熟后破译，应启动向后量子加密迁移规划', '量子计算威胁已被夸大，RSA-2048可继续使用10年以上；只需禁止个人网盘即可', '将所有数据迁移至个人网盘存储可降低内部泄露风险；RSA-2048仅升级为RSA-4096即可应对量子威胁', 'B', '个人网盘绕过企业安全管控，是内部数据泄露的高风险行为；"先存储、后解密"是Gartner 2026年网络安全趋势中明确指出的威胁——攻击者大量收集加密数据等待量子技术破译。量子计算威胁虽未完全成熟但已需提前规划，RSA-4096同样无法抵御量子计算的Shor算法。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D4', '2026年保险行业AI应用已进入初步价值兑现阶段，以下哪项是当前AI在保险行业最成熟的落地应用场景？', 'AI完全替代精算师进行产品定价决策', 'AI辅助智能理赔——通过图像识别定损、规则引擎+大模型自动审核小额案件', 'AI自主设计全新保险产品并直接上线销售', 'AI完全替代核保人员，所有投保申请由AI独立决定是否承保', 'B', '当前AI在保险最成熟的场景是智能理赔，如平安产险车代渠道一分钟智能出单占比93%，众惠相互保险AI自动化精准率97%等。但AI仍需人机协同——精算定价、产品设计、核保决策等核心环节需人工复核。'),
('D4', '关于云原生技术栈的核心组件，以下对应关系正确的是？', '容器编排——Docker；服务网格——Kubernetes；持续交付——Prometheus', '容器运行——Docker；容器编排——Kubernetes；服务网格——Istio', '容器编排——Istio；监控告警——Jenkins；持续交付——Kubernetes', '容器运行——Kubernetes；服务网格——Docker；持续交付——Istio', 'B', 'Docker是容器运行时（构建和运行容器），Kubernetes是容器编排平台（调度和管理容器集群），Istio是服务网格（管理微服务间通信）。Jenkins是CI/CD工具（非监控），Prometheus是监控告警系统（非持续交付）。'),
('D4', '某保险公司构建智能风控系统时采用"大小模型协同"架构：大语言模型负责解析非结构化的理赔描述文本，提取关键特征后交由轻量化判别模型进行欺诈风险评分。这种架构的核心优势是？', '只用大模型即可完成所有任务，小模型是多余的', '大模型擅长非结构化文本理解与推理，小模型擅长结构化判别决策且推理成本低、延迟小，二者协同实现效果与效率的最优平衡', '小模型完全可替代大模型处理文本理解任务', '大小模型必须使用同一套训练数据才能协同工作', 'B', '近80%的智能金融落地案例涉及生成式AI，其中一半采用大小模型协同模式。大模型"大而强"擅长语言理解和推理，小模型"小而美"擅长结构化判别且延迟低、成本低，二者互补实现效果与效率的最优平衡。'),
('D4', '某保险公司计划构建实时风控决策平台，要求：毫秒级欺诈判定响应、支持模型热更新（不停机更新模型版本）、弹性扩展应对促销高峰流量。以下架构设计最合理的是？', '将AI模型嵌入传统单体应用中，模型更新时重新部署整个应用', '采用Kubernetes容器编排部署模型推理服务，通过灰度发布实现模型热更新，利用HPA（水平自动扩缩容）应对流量波动', '将模型直接编译进数据库存储过程中运行，依赖数据库集群扩展能力', '使用批处理方式每小时运行一次模型推理，将结果写入缓存供查询', 'B', 'K8s容器化部署+灰度发布（模型热更新）+HPA（弹性扩缩容）是云原生AI推理服务的标准架构，满足毫秒级响应、不停机更新、弹性扩展三个需求。单体应用模型更新需重新部署整个应用无法热更新，数据库存储过程不适合运行AI模型推理，批处理无法满足毫秒级实时判定。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D1', '根据《保险法》规定，人身保险的投保人对哪些人具有保险利益？', '仅本人、配偶、子女', '本人、配偶、子女、父母，以及与投保人有抚养赡养关系的其他家庭成员', '本人、配偶、子女、父母、兄弟姐妹', '任何自然人均可作为被保险人', 'B', '《保险法》第31条规定，投保人对本人、配偶、子女、父母以及与投保人有抚养、赡养或者扶养关系的家庭其他成员、近亲属具有保险利益。'),
('D1', '农业保险中"物化成本保险"的核心特征是什么？', '以农产品市场价值为理赔依据', '以农业生产投入的直接物化成本为保险金额上限', '以农户预期收入为保障目标', '以政府补贴比例为理赔标准', 'B', '物化成本保险是农业保险的基本形态，以农民在生产过程中投入的种子、化肥、农药、地膜等直接物化成本作为保险金额的上限，保障水平相对较低但保费也低，适合基础保障需求。'),
('D1', '银保监会合并后，我国金融监管格局变为？', '"一行三会"格局', '"一委一行两会"格局', '"一行一局一会"格局', '"一行两会"格局', 'C', '2023年机构改革后，银保监会拆分为国家金融监督管理总局，形成"一行一局一会"格局：中国人民银行（央行）、国家金融监督管理总局、中国证监会，分别负责货币政策与宏观审慎、微观审慎与行为监管、资本市场监管。'),
('D1', '农业保险大灾风险分散机制中，第二层次分散主体是？', '经营农业保险的保险公司', '省级农业保险大灾风险基金', '中央财政支持的国家农业保险大灾风险基金', '国际再保险市场', 'B', '我国农业保险大灾风险分散机制分三层：第一层是保险公司的风险自留与再保险安排，第二层是省级大灾风险基金，第三层是中央层面的大灾风险基金。省级基金在保险公司赔付超过一定阈值后启动补偿。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D2', '微服务架构中"服务网格"(Service Mesh)的核心组件是？', 'API网关和负载均衡器', '数据平面（Sidecar代理）和控制平面', '消息队列和事件总线', '容器编排引擎和镜像仓库', 'B', 'Service Mesh由数据平面（Sidecar代理如Envoy，拦截所有服务间流量）和控制平面（如Istio的Pilot/Mixer/Citadel，管理路由规则、安全策略）组成。API网关是入口层，不属于Mesh核心。'),
('D2', '数据库索引设计原则中，以下哪种场景最适合建立复合索引？', '单列查询频繁，多列组合查询很少', '多列经常一起出现在WHERE条件中，且列的区分度依次递减', '需要对某列做全文检索', '查询结果只需要返回主键值', 'B', '复合索引遵循最左前缀原则，当多列经常组合查询时，应将区分度高的列放在前面、区分度低的放在后面。单列频繁查询用单列索引；全文检索用全文索引；只返回主键的查询可被索引覆盖。'),
('D2', '保险核心系统中，"共保"业务的技术实现要点是？', '所有保单数据只存储在主承保方系统', '各共保方按承保份额独立出单，系统间通过EDI同步', '主承保方统一出单，按份额自动分保给各共保方并同步账务', '共保业务无需在系统中区分，按普通保单处理', 'C', '共保（Co-insurance）由主承保方统一出单，系统需支持按份额自动分保、账务分摊、理赔分摊等逻辑。各共保方不是独立出单，而是在主承保方系统中记录各自的份额和责任。'),
('D2', '系统监控中"RED原则"适用于哪种类型的服务？', '批处理任务', '请求驱动的在线服务', '消息队列消费者', '定时调度任务', 'B', 'RED原则（Rate请求率、Error错误率、Duration延迟）专为请求驱动的在线服务设计。对于批处理和消费者，更适用USE原则（Utilization使用率、Saturation饱和度、Errors错误）。'),
('D2', '某保险理赔系统日均处理1万笔，高峰期TPS达500，数据库CPU持续90%以上，优先采取的措施是？', '增加应用服务器数量', '分析慢查询，优化索引和SQL', '将数据库迁移到更大规格的服务器', '引入消息队列异步处理', 'B', '数据库CPU高通常说明SQL执行效率低。应先分析慢查询日志，优化索引和SQL语句，这是成本最低效果最好的方案。增加应用服务器无法解决数据库瓶颈；迁移大规格服务器是最后手段；异步处理适合非实时场景但理赔处理通常需要实时响应。'),
('D2', '代码审查中，以下哪种情况属于"安全缺陷"而非"代码规范"问题？', '变量命名不符合驼峰规范', '函数复杂度过高（圈复杂度>15）', 'SQL语句使用字符串拼接而非参数化查询', '缺少必要的代码注释', 'C', 'SQL字符串拼接导致SQL注入漏洞，属于OWASP Top 1的安全缺陷。变量命名、圈复杂度、注释属于代码规范和可维护性问题，不直接构成安全风险。'),
('D2', 'TDD（测试驱动开发）的正确实践步骤是？', '先写实现代码→写测试→重构', '先写测试（红）→写实现代码（绿）→重构', '先写设计文档→编码→测试', '先写集成测试→单元测试→实现代码', 'B', 'TDD的核心循环是"红-绿-重构"：先写会失败的测试（红），再写最少量代码让测试通过（绿），然后重构改善代码质量。这个循环保证每行实现代码都有测试覆盖。'),
('D2', '分布式系统中"幂等性"设计的关键作用是？', '提高系统响应速度', '确保同一操作重复执行不会产生不同结果，安全应对重试', '减少数据库存储空间占用', '简化前端调用逻辑', 'B', '幂等性确保同一请求执行一次和多次效果相同。在分布式系统中，网络超时导致的重试、消息重复投递等场景下，幂等性可防止重复扣款、重复出单等严重业务问题。'),
('D2', '需求分析阶段获取用户需求时，以下哪种方法最适合发现"用户自己都说不清楚"的隐性需求？', '发放结构化问卷让用户勾选已有选项', '在现场观察用户的实际操作流程，记录工作细节和痛点', '让用户阅读系统需求规格说明书后反馈意见', '仅通过邮件沟通收集用户需求', 'B', '隐性需求是用户未明确表达甚至未意识到的需求。结构化问卷、文档反馈、邮件沟通都依赖用户的显性表达，难以捕捉隐性信息。现场观察（情境调查）通过直接观看用户操作，发现用户习以为常但实际低效的工作方式，是挖掘隐性需求最有效的方法。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D3', '零信任架构（Zero Trust）的核心理念是？', '内网完全可信，外网不可信', '"永不信任，始终验证"，对任何访问请求均进行身份验证和授权', '依赖防火墙和VPN建立安全边界', '仅对远程访问进行额外认证', 'B', '零信任架构由Forrester Research提出，核心原则是"Never trust, always verify"。无论请求来自内网还是外网，都需要验证身份、设备状态和访问权限，取消隐式信任区域。传统边界安全模型假设内网可信，零信任彻底否定了这一假设。'),
('D3', '根据《个人信息保护法》，保险公司处理客户敏感个人信息（如健康数据）时，必须？', '仅需在隐私政策中告知即可', '取得个人的单独同意，并告知处理的必要性及影响', '只需获得客户口头同意', '只要在合同条款中列明即可', 'B', '《个人信息保护法》第29条规定，处理敏感个人信息应当取得个人的单独同意；第30条要求告知处理敏感个人信息的必要性以及对个人权益的影响。健康数据属于敏感个人信息，不能仅通过隐私政策或合同条款笼统授权。'),
('D3', 'SOC 2报告中，哪种类型提供了控制措施实际运行有效性的审计结论？', 'SOC 2 Type I', 'SOC 2 Type II', 'SOC 2 Type III', 'SOC 2 Type IV', 'B', 'SOC 2 Type I仅审计控制措施在某一时间点的设计是否合理，Type II则在一定观察期内（通常6个月以上）验证控制措施是否实际运行有效。Type III/IV不是正式的SOC 2报告类型。'),
('D3', '社会工程学攻击中"尾随"(Tailgating)的防范措施是？', '安装防火墙和IDS', '部署门禁系统并要求一人一卡，配合安全意识培训', '加强密码复杂度要求', '实施网络分段', 'B', '尾随攻击是指未经授权人员紧随有权限人员进入受控区域。防范措施主要是物理安全控制：门禁系统一人一卡、旋转门、安全岗核查，以及安全意识培训让员工主动阻止尾随行为。防火墙、密码、网络分段都是逻辑安全措施，无法防范物理尾随。');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('D4', '大语言模型(LLM)的"幻觉"(Hallucination)问题在保险场景中最大的风险是？', '模型推理速度变慢', '生成看似合理但不真实的保险条款或理赔结论，导致合规风险', '增加模型训练成本', '导致系统无法启动', 'B', 'LLM幻觉是指模型生成听起来合理但事实上错误的内容。在保险场景中，如果用于条款解读或理赔建议，可能产生不存在的条款引用或错误的理赔结论，严重违反保险监管要求，带来合规处罚和客户纠纷风险。'),
('D4', 'RAG（检索增强生成）技术相比纯LLM的核心优势是？', '模型参数量更小', '通过检索外部知识库提供事实依据，减少幻觉，答案可追溯', '不需要GPU资源', '训练数据要求更少', 'B', 'RAG在生成前先从知识库检索相关文档，将检索结果作为上下文输入LLM，使生成内容基于真实文档而非模型记忆，大幅减少幻觉。同时答案可追溯到具体文档来源，满足保险行业对可解释性和合规性的要求。'),
('D4', '保险行业采用区块链技术，最适合解决的核心痛点是？', '提升前端页面渲染速度', '再保和共保场景中的多方信任与对账效率', '减少客户投诉量', '降低服务器运维成本', 'B', '区块链的不可篡改、多方共识、可追溯特性，天然适合再保/共保中涉及多个参与方、需要频繁对账结算的场景。通过智能合约自动执行分保规则和对账逻辑，可以大幅减少人工对账成本和纠纷。'),
('D4', '边缘计算在农业保险物联网场景中的核心价值是？', '替代云端数据中心的所有功能', '在田间地头就近处理传感器数据，降低传输延迟，支持实时预警', '只用于数据存储备份', '主要用于提高网络安全防护能力', 'B', '农业保险物联网（如气象站、土壤传感器）产生大量实时数据。边缘计算在数据源附近（如田间网关）进行初步处理和异常检测，减少数据传输量、降低延迟，在霜冻、暴雨等灾害来临时实现分钟级预警，而无需等待数据上传云端处理。');
